-- SCRIPT'S BEBIDA

-- LISTAR BEBIDAS
CREATE PROCEDURE [dbo].[spListarBebidas]
AS
BEGIN
    SELECT 
        BebidaID,
        Nombre_Bebida, 
        Precio,
        TamañoBebida,
        EstadoBebida,
		TipobebidaID
    FROM Bebida
    WHERE EstadoBebida = '1';
END;
GO

-- AGREGAR BEBIDAS

CREATE PROCEDURE [dbo].[spInsertarBebida]
	@BebidaID INT,
    @Nombre_Bebida VARCHAR(50),
    @Precio DECIMAL(10, 2),
    @TamañoBebida VARCHAR(20),
    @EstadoBebida BIT,
	@TipobebidaID INT
AS
BEGIN
    INSERT INTO Bebida (BebidaID ,Nombre_Bebida, Precio, TamañoBebida, EstadoBebida, TipobebidaID)
    VALUES (@BebidaID ,@Nombre_Bebida, @Precio, @TamañoBebida, @EstadoBebida, @TipobebidaID);
END;
GO

-- MODIFICAR BEBIDAS

CREATE PROCEDURE [dbo].[spEditarBebida]
	@BebidaID INT,
    @Nombre_Bebida VARCHAR(50),
    @Precio DECIMAL(10, 2),
    @TamañoBebida VARCHAR(20),
    @EstadoBebida BIT
AS
BEGIN
    UPDATE Bebida
    SET BebidaID = @BebidaID,
        Nombre_Bebida = @Nombre_Bebida,
        Precio = @Precio,
        TamañoBebida = @TamañoBebida,
        EstadoBebida = @EstadoBebida
    WHERE BebidaID = @BebidaID;
END;
GO

-- DESHABILITAR BEBIDAS

CREATE PROCEDURE [dbo].[spDeshabilitarBebida]
    @BebidaID INT
AS
BEGIN
    UPDATE Bebida
    SET 
        EstadoBebida = 0
    WHERE BebidaID = @BebidaID;
END;
GO


