--Procedimientos CompraInsumos

--listar
CREATE PROCEDURE [dbo].[spListarCompraReq]
AS
BEGIN
    SELECT 
        c.ComprainsumosID,
        c.Encargado,
        c.FechaCompra,
        c.MetodoPago,
        c.MontoTotal,
        c.RequerimientoDeInsumoID,
        r.FechaRegistro AS FechaRequerimiento, -- ejemplo
        c.ProveedorID,
        p.NombreProveedor,
        c.EstadoCompra
    FROM Comprainsumos c
    INNER JOIN Proveedor p ON c.ProveedorID = p.ProveedorID
    INNER JOIN RequerimientoDeInsumo r ON c.RequerimientoDeInsumoID = r.RequerimientoDeInsumoID;
END;
GO

--Registrar
CREATE PROCEDURE [dbo].[spRegistrarCompraReq]
	@ComprainsumosID INT,
    @Encargado VARCHAR(100),
    @FechaCompra DATETIME,
    @MetodoPago VARCHAR(50),
    @MontoTotal DECIMAL(10,2),
	@EstadoCompra BIT,
    @RequerimientoDeInsumoID INT,
    @ProveedorID INT
AS
BEGIN
    INSERT INTO Comprainsumos(ComprainsumosID ,Encargado, FechaCompra, MetodoPago, MontoTotal, EstadoCompra, RequerimientoDeInsumoID, ProveedorID)
    VALUES (@ComprainsumosID,@Encargado, @FechaCompra, @MetodoPago, @MontoTotal, @EstadoCompra, @RequerimientoDeInsumoID, @ProveedorID);

END;
GO

--Anular
CREATE PROCEDURE [dbo].[spAnularCompraReq]
    @ComprainsumosID INT
AS
BEGIN
    UPDATE Comprainsumos
    SET EstadoCompra = 0
    WHERE ComprainsumosID = @ComprainsumosID;
END;
GO


--Procedimientos Detalle REQUERIMIENTO

-- LISTAR DETALLE REQUERIMIENTO
CREATE PROCEDURE [dbo].[spListarDetalleReq] 
    @RequerimientoDeInsumoID INT
AS
BEGIN
    SELECT 
        d.DetallesreqID,
        d.RequerimientoDeInsumoID, 
        d.InsumosID,
        i.Nombre,
        d.Cantidad
    FROM Detallesreq d
    INNER JOIN Insumos i ON d.InsumosID = i.InsumosID
    WHERE d.RequerimientoDeInsumoID = @RequerimientoDeInsumoID; -- ← corregido aquí
END;
GO

-- INSERTAR DETALLE REQUERIMIENTO

CREATE PROCEDURE [dbo].[spInsertarDetalleReq]
    @RequerimientoDeInsumoID INT,
    @InsumosID INT,
    @Cantidad VARCHAR(50)
AS
BEGIN
    INSERT INTO Detallesreq (RequerimientoDeInsumoID, InsumosID, Cantidad)
    VALUES (@RequerimientoDeInsumoID, @InsumosID, @Cantidad);
END;
GO

