    @EncargadoalmacenID INT,
    @Nombre VARCHAR(50),
    @DNI INT,
    @Numero VARCHAR(9),
    @FechaIngreso DATETIME,
    @Estado BIT
AS
BEGIN
    UPDATE Encargadoalmacen
    SET EncargadoalmacenID = @EncargadoalmacenID,
        Nombre = @Nombre,
        DNI = @DNI,
        Numero = @Numero,
        FechaRegistro = @FechaIngreso,
