-- CORE'S

-- SCRIPT'S CORE - ORDENPEDIDO

-- LISTAR ORDENPEDIDO

CREATE PROCEDURE [dbo].[spListarOrdenPedido]
AS
BEGIN
    SELECT 
        o.OrdenpedidoID,
        o.Fecha,
        o.NroMesa,
        o.Total,
        o.Estado,
		m.MeseroID,
        m.Nombre_Mesero
    FROM Ordenpedido o
    INNER JOIN Mesero m ON o.MeseroID = m.MeseroID
    WHERE o.Estado = '1'
    ORDER BY o.Fecha DESC;
END;
GO

-- REGISTRAR ORDENPEDIDO

CREATE PROCEDURE [dbo].[spAgregarOrdenPedido]
	@OrdenpedidoID INT,
    @Fecha DATETIME,
    @NroMesa INT,
    @Total DECIMAL(10,2),
    @Estado BIT,
    @MeseroID INT
AS
BEGIN
    INSERT INTO OrdenPedido (OrdenpedidoID ,Fecha, NroMesa, Total, Estado, MeseroID)
    VALUES (@OrdenpedidoID ,@Fecha, @NroMesa, @Total, @Estado, @MeseroID);
END;
GO

