    @Total DECIMAL(10, 2),
    @EstadoPedido BIT,
    @MeseroID INT
AS
BEGIN
    UPDATE OrdenPedido
    SET OrdenpedidoID = @OrdenpedidoID,
        NroMesa = @NroMesa,
        Total = @Total,
        Estado = @EstadoPedido,
        MeseroID = @MeseroID
    WHERE OrdenpedidoID = @OrdenpedidoID;
END;
