-- LISTAR DETALLEPEDIDO

CREATE PROCEDURE [dbo].[spListarDetallePorPedido]
    @OrdenpedidoID INT
AS
BEGIN
    SELECT 
        dp.OrdenpedidoID,
        dp.DetallepedidoID,
        dp.PlatilloID,
        p.NombrePlatillo,
        dp.Cantidad,
        p.Precio AS Precio,
        dp.Subtotal
    FROM Detallepedido dp
    INNER JOIN Platillo p ON dp.PlatilloID = p.PlatilloID
    WHERE dp.OrdenpedidoID = @OrdenpedidoID
END
GO

