-- LISTAR COMPROBANTE

CREATE PROCEDURE [dbo].[spListarComprobantes]
AS
BEGIN
    SELECT 
        cp.ComprobanteDeVentaID,
		c.ClienteID,
        c.Nombre_Cliente AS NombreCliente,
        cp.OrdenpedidoID,
        cp.TipoComprobante,
        cp.FechaEmision,
        cp.MontoTotal,
        cp.EstadoComprobante
    FROM ComprobanteDeVenta cp
    INNER JOIN Cliente c ON cp.ClienteID = c.ClienteID
    ORDER BY cp.ComprobanteDeVentaID DESC;
END;
GO


-- INSERTAR COMPROBANTE

CREATE PROCEDURE [dbo].[spInsertarComprobante]
	@ComprobanteDeVentaID INT,  
    @ClienteID INT,
    @OrdenpedidoID INT,
    @TipoComprobante VARCHAR(50),
    @FechaEmision DATE,
    @MontoTotal DECIMAL(10,2),
    @EstadoComprobante BIT
AS
BEGIN
    INSERT INTO ComprobanteDeVenta (ComprobanteDeVentaID ,ClienteID, OrdenpedidoID, TipoComprobante, FechaEmision, MontoTotal, EstadoComprobante)
    VALUES (@ComprobanteDeVentaID ,@ClienteID, @OrdenpedidoID, @TipoComprobante, @FechaEmision, @MontoTotal, @EstadoComprobante);
END;
GO

-- ANULAR COMPROBANTE

CREATE PROCEDURE [dbo].[spAnularComprobante]
    @ComprobanteDeVentaID INT
AS
BEGIN
    UPDATE ComprobanteDeVenta
    SET 
        EstadoComprobante = 0 -- Cambiar a 0 para indicar que está anulado
    WHERE ComprobanteDeVentaID = @ComprobanteDeVentaID;
END;
GO

