CREATE PROCEDURE [dbo].[spListarRequerimientos]
AS
BEGIN
    SELECT 
        r.RequerimientoDeInsumoID,
        r.FechaRegistro,
        r.Estado,
		r.IDEncargado,
        e.Nombre AS NombreEncargado
    FROM RequerimientoDeInsumo r
    INNER JOIN Encargadoalmacen e ON r.IDEncargado = e.EncargadoalmacenID
	--where R.Estado = '1'
END;
GO

-- REGISTRAR REQUERIMIENTO INSUMOS
